#!/usr/bin/env bash
# workflow-2.sh — 个案概念化流程（把症状/史/关系/情境组织成可工作的理解 + 计划） SOP walkthrough for 心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大)"
WORKFLOW="个案概念化流程（把症状/史/关系/情境组织成可工作的理解 + 计划）"

usage() {
  cat <<EOF
workflow-2.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-2.sh             # interactive
  ./workflow-2.sh --dry-run
  ./workflow-2.sh --json
  ./workflow-2.sh --explain
  ./workflow-2.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "个案概念化流程（把症状/史/关系/情境组织成可工作的理解 + 计划）" 工作流。

一句话: 把一堆零散的信息（症状、发展史、关系模式、当下情境、来访者的资源）组织成一个「为什么这个人现在这样、什么在维持这个问题、从哪入手」的可工作因果理解——这是**跨流派的核心临床能力**，不是某一派的专利。

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 治疗关系 / 共同要素 > 单一技术: 这一行的资深人默认「治疗关系的质量、共情、期望、来访者因素」这些**跨流派共有的共同要素**对疗效的解释力,可能不亚于任一流派的特定技术 —— 所以「学对了流派」从来不够,「谁来做、和来访者建立了什么
  • 症状是有功能 / 是适应,不是单纯的「病」: 这一行的人看一个症状,默认先问「它在为这个人 / 这个系统**做什么**」—— 症状常是某个困境下能找到的最优解、是适应而非缺陷,去病理化地理解它,比急着「消除」它更接近治疗。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**描述问题（presenting problem）**：把来访者带来的困扰具体化——什么症状 / 行为 / 痛苦，频率、强度、情境、对生活的影响。**输出**=问题的清晰描述（而非模糊的「情绪不好」）。"
  "**收集相关信息（4 个维度）**：症状层 + 发展 / 早年史 + 关系模式（含治疗关系里观察到的）+ 当下情境（压力源、资源、文化背景）。**输出**=四个维度的素材。"
  "**找模式 / 提假设（formulation 核心动作）**：问「**什么在维持这个问题**」——是认知模式（CBT）、早年关系的重复（动力学）、家庭系统的功能（系统式）、还是创伤的身体印记（创伤取向）？不同流派提供不同的「解释模板」，但动作相同：从素材里提出一个因果假设。"
  "**写成可工作的概念化 + 接出治疗计划**：把假设落成文字（很多取向有概念化图 / 模板），明确「从哪个点切入阻力最小」，治疗计划直接从概念化导出。"
  "**持续修订（概念化是假设不是结论）**：每次会谈拿新信息回测概念化——对了就深化，不对就改。把它当**可证伪的工作假设**。"
)
declare -a FAILURE_MODES=(
  "**「概念化 = 诊断」**：把「来访者是抑郁症」当成概念化——后果是治疗只剩「对抑郁症做点什么」，没有「对这个人」的理解。避免：诊断完，必答「什么在维持、资源在哪、从哪切入」。"
  "**「概念化写死不改」**：第一版当定论——后果是对不符合假设的信息视而不见。避免：每次会谈拿新信息回测，把它当可证伪假设。"
  "**「单一流派锁死」**：只会用自己流派的解释模板硬套所有个案——后果是有些来访者被概念化得很勉强。避免：知道自己流派的模板是「一种视角」不是「真相」。"
  "**「只从内容提取、忽略过程」**：只分析来访者讲的事，不看治疗关系里的模式与自己的反移情——丢掉了最直接的关系样本。避免：把「房间里发生的」纳入概念化素材。"
  "**CLI 化暗示**：抽进概念化自检——「我能用一两句话说出『什么在维持这个问题』吗？」「我的概念化是文字成形的、还是只在脑子里？」「最近一次会谈的信息，符不符合我的概念化？不符合的话我改了吗？」"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-2-walkthrough"
fi
